/**
 * General-purpose TrUAPI methods for feature detection, navigation, and
 * notifications.
 *
 * # Wire id reservations
 *
 * Slots 68-75 are reserved for legacy Novasama methods TrUAPI does not
 * implement; if we ever need them, annotate the trait method with
 * `#[wire(id = ...)]` matching the slot below.
 *
 * - 68-69: `remote_preimage_submit` (request, response)
 * - 70-71: `host_jsonrpc_message_send` (request, response)
 * - 72-75: `host_jsonrpc_message_subscribe` (start, stop, interrupt, receive)
 */
export class TrUApiCallsClient {
  constructor(private readonly transport: TrUApiTransport) {}

  /**
   * Negotiates the wire codec version with the product. Required for
   * compatibility with `@novasamatech/host-api`-built products that gate
   * "connected" state on a successful handshake response.
   *
   * Default impl accepts codec version `1` (Novasama's `JAM_CODEC_PROTOCOL_ID`)
   * and rejects everything else with `UnsupportedProtocolVersion`. Hosts that
   * want to gate handshake on additional preconditions can override.
   */
  async handshake(): Promise<Result<undefined, T.V02HostHandshakeError>> {
    const result = await this.transport.request<
      S.ResultPayload<undefined, T.V02HostHandshakeError>
    >({
      method: "host_handshake",
      payload: T.HostHandshakeRequest.enc({
        tag: "V1",
        value: { codecVersion: this.transport.codecVersion },
      }),
      decodeResponse: (payload) =>
        S.indexedTaggedUnion({
          V1: [0, S.result(S.unit, T.V02HostHandshakeError)] as const,
        }).dec(payload).value,
    });
    return result.success ? ok(result.value) : err(result.value);
  }

  /** Queries whether the host supports a specific feature. */
  async featureSupported(
    request: T.V01HostFeatureSupportedRequest,
  ): Promise<Result<T.V01HostFeatureSupportedResponse, T.GenericError>> {
    const result = await this.transport.request<
      S.ResultPayload<T.V01HostFeatureSupportedResponse, T.GenericError>
    >({
      method: "host_feature_supported",
      payload: T.HostFeatureSupportedRequest.enc({ tag: "V1", value: request }),
      decodeResponse: (payload) =>
        S.indexedTaggedUnion({
          V1: [
            0,
            S.result(T.V01HostFeatureSupportedResponse, T.GenericError),
          ] as const,
        }).dec(payload).value,
    });
    return result.success ? ok(result.value) : err(result.value);
  }

  /** Sends a push notification to the user. */
  async pushNotification(
    request: T.V01HostPushNotificationRequest,
  ): Promise<Result<undefined, T.GenericError>> {
    const result = await this.transport.request<
      S.ResultPayload<undefined, T.GenericError>
    >({
      method: "host_push_notification",
      payload: T.HostPushNotificationRequest.enc({ tag: "V1", value: request }),
      decodeResponse: (payload) =>
        S.indexedTaggedUnion({
          V1: [0, S.result(S.unit, T.GenericError)] as const,
        }).dec(payload).value,
    });
    return result.success ? ok(result.value) : err(result.value);
  }

  /** Requests the host to open a URL. */
  async navigateTo(
    request: T.V01HostNavigateToRequest,
  ): Promise<Result<undefined, T.V01HostNavigateToError>> {
    const result = await this.transport.request<
      S.ResultPayload<undefined, T.V01HostNavigateToError>
    >({
      method: "host_navigate_to",
      payload: T.HostNavigateToRequest.enc({ tag: "V1", value: request }),
      decodeResponse: (payload) =>
        S.indexedTaggedUnion({
          V1: [0, S.result(S.unit, T.V01HostNavigateToError)] as const,
        }).dec(payload).value,
    });
    return result.success ? ok(result.value) : err(result.value);
  }
}

export interface TrUApiClient {
  readonly accountManagement: AccountManagementClient;
  readonly chainInteraction: ChainInteractionClient;
  readonly chat: ChatClient;
  readonly entropyDerivation: EntropyDerivationClient;
  readonly localStorage: LocalStorageClient;
  readonly payment: PaymentClient;
  readonly permissions: PermissionsClient;
  readonly preimage: PreimageClient;
  readonly signing: SigningClient;
  readonly statementStore: StatementStoreClient;
  readonly trUApiCalls: TrUApiCallsClient;
}

/** Creates the generated client facade by binding each service namespace to the
 * shared transport instance. */
export function createClient(transport: TrUApiTransport): TrUApiClient {
  return {
    accountManagement: new AccountManagementClient(transport),
    chainInteraction: new ChainInteractionClient(transport),
    chat: new ChatClient(transport),
    entropyDerivation: new EntropyDerivationClient(transport),
    localStorage: new LocalStorageClient(transport),
    payment: new PaymentClient(transport),
    permissions: new PermissionsClient(transport),
    preimage: new PreimageClient(transport),
    signing: new SigningClient(transport),
    statementStore: new StatementStoreClient(transport),
    trUApiCalls: new TrUApiCallsClient(transport),
  };
}
